#!/usr/bin/env bash
# Verify that config/graph.sql and config/graph_local.sql are up to date
# with the ontology. Runs the DDL generators and diffs against checked-in files.
set -euo pipefail

ORBIT="${1:-cargo run --bin orbit --}"
FAILED=0

check_file() {
    local cmd="$1"
    local file="$2"
    local label="$3"

    # Verify the file has the autogenerated header.
    if ! head -1 "$file" | grep -qE '^-- SCHEMA_VERSION=[0-9]+ \[AUTOGENERATED'; then
        echo "❌ $file is missing the AUTOGENERATED header."
        echo "   Regenerate with: mise schema:generate:ddl${label:+:$label}"
        FAILED=1
        return
    fi

    local generated
    generated=$(eval "$cmd" 2>/dev/null)

    # Normalize trailing whitespace for comparison.
    local file_content
    file_content=$(sed -e :a -e '/^\n*$/{$d;N;ba' -e '}' "$file")
    local gen_content
    gen_content=$(printf '%s' "$generated" | sed -e :a -e '/^\n*$/{$d;N;ba' -e '}')

    if [ "$file_content" != "$gen_content" ]; then
        echo "❌ $file is out of date with the ontology."
        echo "   Regenerate with: mise schema:generate:ddl${label:+:$label}"
        diff --unified=3 <(echo "$file_content") <(echo "$gen_content") | head -30
        FAILED=1
    else
        echo "✅ $file is up to date."
    fi
}

check_file "$ORBIT debug ddl" "config/graph.sql" ""
check_file "$ORBIT debug ddl-local" "config/graph_local.sql" "local"

exit $FAILED
